## 💻 핵심 코드 구현

### 1. Notion Client 래퍼

**utils/notion_client.py:**

```python
"""
Notion API Client Wrapper
간단하고 재사용 가능한 Notion API 래퍼
"""

from notion_client import Client
from typing import Dict, List, Optional
import os
from dotenv import load_dotenv

# 환경변수 로드
load_dotenv()


class NotionClient:
    """
    Notion API를 쉽게 사용하기 위한 래퍼 클래스

    철학:
    - 복잡한 Notion API를 단순화
    - 에러 핸들링 자동화
    - 재사용 가능한 메서드 제공
    """

    def __init__(self):
        """Notion Client 초기화"""
        self.token = os.getenv("NOTION_TOKEN")
        if not self.token:
            raise ValueError("NOTION_TOKEN이 .env에 설정되지 않았습니다.")

        self.client = Client(auth=self.token)
        self.parent_page_id = os.getenv("PARENT_PAGE_ID")

    def create_database(
        self, 
        title: str, 
        properties: Dict,
        parent_page_id: Optional[str] = None
    ) -> Dict:
        """
        Notion Database 생성

        Args:
            title: Database 제목
            properties: 필드 정의 (스키마)
            parent_page_id: 부모 페이지 ID (선택)

        Returns:
            생성된 Database 정보
        """
        parent_id = parent_page_id or self.parent_page_id

        try:
            response = self.client.databases.create(
                parent={
                    "type": "page_id",
                    "page_id": parent_id
                },
                title=[
                    {
                        "type": "text",
                        "text": {"content": title}
                    }
                ],
                properties=properties
            )

            print(f"✅ Database '{title}' 생성 완료!")
            print(f"   ID: {response['id']}")
            return response

        except Exception as e:
            print(f"❌ Database 생성 실패: {e}")
            raise

    def update_database_properties(
        self,
        database_id: str,
        properties: Dict
    ) -> Dict:
        """
        Database 속성(필드) 업데이트

        Args:
            database_id: Database ID
            properties: 추가/수정할 필드

        Returns:
            업데이트된 Database 정보
        """
        try:
            response = self.client.databases.update(
                database_id=database_id,
                properties=properties
            )

            print(f"✅ Database 속성 업데이트 완료!")
            return response

        except Exception as e:
            print(f"❌ 속성 업데이트 실패: {e}")
            raise

    def create_page(
        self,
        database_id: str,
        properties: Dict,
        children: Optional[List] = None
    ) -> Dict:
        """
        Database에 새 페이지 생성

        Args:
            database_id: Database ID
            properties: 페이지 속성 (필드 값)
            children: 페이지 내용 블록 (선택)

        Returns:
            생성된 페이지 정보
        """
        payload = {
            "parent": {"database_id": database_id},
            "properties": properties
        }

        if children:
            payload["children"] = children

        try:
            response = self.client.pages.create(**payload)
            print(f"✅ 페이지 생성 완료!")
            return response

        except Exception as e:
            print(f"❌ 페이지 생성 실패: {e}")
            raise

    def query_database(
        self,
        database_id: str,
        filter_obj: Optional[Dict] = None,
        sorts: Optional[List] = None
    ) -> List[Dict]:
        """
        Database 쿼리 (검색)

        Args:
            database_id: Database ID
            filter_obj: 필터 조건
            sorts: 정렬 조건

        Returns:
            검색된 페이지 리스트
        """
        payload = {"database_id": database_id}

        if filter_obj:
            payload["filter"] = filter_obj
        if sorts:
            payload["sorts"] = sorts

        try:
            response = self.client.databases.query(**payload)
            return response["results"]

        except Exception as e:
            print(f"❌ Database 쿼리 실패: {e}")
            raise


# 싱글톤 인스턴스
notion = NotionClient()
```

