### 2. Database 생성 스크립트

**scripts/01_create_database.py:**

```python
"""
Market Notes Database 생성 스크립트

역할:
1. Notion에 Market Notes DB 생성
2. 기본 스키마 적용
3. DB ID를 .env에 저장
"""

import sys
import os

# 상위 디렉토리를 Python 경로에 추가
sys.path.append(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))

from utils.notion_client import notion
from config.notion_schema import MARKET_NOTES_PROPERTIES


def create_market_notes_database():
    """
    Market Notes Database 생성
    """
    print("=" * 60)
    print("🚀 Market Notes Database 생성 시작")
    print("=" * 60)

    # Database 생성
    db_response = notion.create_database(
        title="📝 Market Notes",
        properties=MARKET_NOTES_PROPERTIES
    )

    database_id = db_response["id"]

    # .env 파일에 DB ID 저장
    env_path = ".env"

    # 기존 .env 읽기
    with open(env_path, "r", encoding="utf-8") as f:
        lines = f.readlines()

    # MARKET_NOTES_DB_ID 업데이트
    updated = False
    for i, line in enumerate(lines):
        if line.startswith("MARKET_NOTES_DB_ID="):
            lines[i] = f"MARKET_NOTES_DB_ID={database_id}\n"
            updated = True
            break

    # 없으면 추가
    if not updated:
        lines.append(f"\nMARKET_NOTES_DB_ID={database_id}\n")

    # .env 저장
    with open(env_path, "w", encoding="utf-8") as f:
        f.writelines(lines)

    print("\n" + "=" * 60)
    print("✅ 완료!")
    print(f"   Database ID: {database_id}")
    print(f"   .env 파일에 저장됨")
    print("=" * 60)

    return database_id


if __name__ == "__main__":
    create_market_notes_database()
```

